// IVX FULL VISITOR JOURNEY — LIVE PROOF
// Simulates one real visitor from Google search → registration → member → investor → CRM → analytics → follow-up → dashboard

const SUPABASE_URL = "https://kvclcdjmjghndxsngfzb.supabase.co";
const ANON_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzMxOTQwMjcsImV4cCI6MjA4ODc3MDAyN30.OLDwa21VHQNs151AD-8k--_HigQ2d-N7yJfFn5UeNPk";
const SERVICE_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzE5NDAyNywiZXhwIjoyMDg4NzcwMDI3fQ.TaTRyViK-8sv3R_g1Me08sEjnyMskGXKF0u-I-PTaQ8";
const API = "https://api.ivxholding.com";
const results = {};
const ts = () => new Date().toISOString();

async function sbFetch(path, opts = {}) {
  const r = await fetch(`${SUPABASE_URL}${path}`, {
    ...opts,
    headers: {
      "apikey": SERVICE_KEY,
      "Authorization": `Bearer ${SERVICE_KEY}`,
      "Content-Type": "application/json",
      ...(opts.headers || {})
    }
  });
  const status = r.status;
  let body;
  try { body = await r.json(); } catch { body = await r.text(); }
  return { status, body };
}

// === STEP 1: Google search query (intent discovery) ===
console.log("\n=== STEP 1: Google Search Query ===");
const searchQuery = "miami investment property for sale";
const searchPayload = {
  keyword: searchQuery,
  country: "US",
  city: "Miami",
  language: "en",
  monthly_volume: 8100,
  cpc: 2.40,
  competition: 0.65,
  intent_score: 92,
  commercial_score: 88,
  roi_score: 85,
  category: "Miami Investment",
  intent_cluster: "INVEST",
  buying_intent_score: 78,
  investment_intent_score: 92,
  capital_size_estimate: "500k-2M",
  probability_of_registration: 0.34,
  probability_of_investment: 0.12,
  trend_7d: 5,
  trend_30d: 12,
  trend_90d: 8,
  discovered_at: ts()
};

// Insert into intent_keywords table
let kwRes = await sbFetch("/rest/v1/intent_keywords?select=id", {
  method: "POST",
  body: JSON.stringify(searchPayload)
});
results.step1_search = { query: searchQuery, http: kwRes.status, body: kwRes.body };
console.log("Search query logged:", kwRes.status, JSON.stringify(kwRes.body).slice(0, 200));

// === STEP 2: Landing page opened ===
console.log("\n=== STEP 2: Landing Page Opened ===");
const landingSlug = "invest-miami";
const landingRes = await fetch(`${API}/api/ivx/intent/landing/${landingSlug}?track=true&country=US&language=en&device=mobile&source=google`, {
  method: "GET",
  headers: { "Content-Type": "application/json" }
});
const landingStatus = landingRes.status;
let landingBody;
try { landingBody = await landingRes.json(); } catch { landingBody = await landingRes.text(); }
results.step2_landing = { slug: landingSlug, http: landingStatus, body: typeof landingBody === 'object' ? JSON.stringify(landingBody).slice(0, 300) : String(landingBody).slice(0, 300) };
console.log("Landing page:", landingStatus, typeof landingBody === 'object' ? JSON.stringify(landingBody).slice(0, 200) : String(landingBody).slice(0, 200));

// === STEP 3-6: Visitor intelligence (country, language, device, time) ===
console.log("\n=== STEP 3-6: Visitor Intelligence ===");
const visitorPayload = {
  visitor_id: `vis-${Date.now()}`,
  country: "US",
  city: "Miami",
  language: "en",
  device: "mobile",
  browser: "Chrome",
  os: "iOS",
  ip_hash: "hash_" + Math.random().toString(36).slice(2, 12),
  referrer: "https://google.com/search?q=miami+investment+property",
  landing_page: `/invest-miami`,
  search_query: searchQuery,
  pages_viewed: 1,
  session_start: ts(),
  is_returning: false,
  created_at: ts()
};

let visRes = await sbFetch("/rest/v1/visitor_intelligence?select=id", {
  method: "POST",
  body: JSON.stringify(visitorPayload)
});
results.step3_6_visitor = { http: visRes.status, body: visRes.body, visitor_id: visitorPayload.visitor_id };
console.log("Visitor tracked:", visRes.status, JSON.stringify(visRes.body).slice(0, 200));

// === STEP 7: AI conversation started ===
console.log("\n=== STEP 7: AI Conversation Started ===");
const chatRes = await fetch(`${API}/public/chat`, {
  method: "POST",
  headers: { "Content-Type": "application/json" },
  body: JSON.stringify({
    message: "I'm interested in investing in Miami real estate. What ROI can I expect?",
    roomId: "visitor-" + visitorPayload.visitor_id,
    visitorId: visitorPayload.visitor_id,
    country: "US",
    language: "en"
  })
});
const chatStatus = chatRes.status;
let chatBody;
try { chatBody = await chatRes.json(); } catch { chatBody = await chatRes.text(); }
results.step7_ai_chat = { http: chatStatus, body: typeof chatBody === 'object' ? JSON.stringify(chatBody).slice(0, 400) : String(chatBody).slice(0, 400) };
console.log("AI chat:", chatStatus, typeof chatBody === 'object' ? JSON.stringify(chatBody).slice(0, 300) : String(chatBody).slice(0, 300));

// === STEP 8: Registration created ===
console.log("\n=== STEP 8: Registration Created ===");
const regEmail = `visitor${Date.now()}@gmail.com`;
const regPayload = {
  email: regEmail,
  full_name: "John Visitor",
  phone: "+1-305-555-0142",
  country: "US",
  city: "Miami",
  language: "en",
  investor_type: "real_estate",
  capital_range: "500k-2M",
  interests: ["Real Estate Investment", "Miami Investment", "Passive Income"],
  source: "google_search",
  search_query: searchQuery,
  landing_page: "/invest-miami",
  visitor_id: visitorPayload.visitor_id,
  status: "registered",
  created_at: ts()
};

let regRes = await sbFetch("/rest/v1/waitlist?select=id", {
  method: "POST",
  body: JSON.stringify(regPayload)
});
results.step8_registration = { http: regRes.status, body: regRes.body, email: regEmail };
console.log("Registration:", regRes.status, JSON.stringify(regRes.body).slice(0, 200));

// === STEP 9: Member created ===
console.log("\n=== STEP 9: Member Created ===");
const memberPayload = {
  email: regEmail,
  full_name: "John Visitor",
  phone: "+1-305-555-0142",
  country: "US",
  city: "Miami",
  language: "en",
  member_type: "investor",
  status: "active",
  source: "intent_engine",
  visitor_id: visitorPayload.visitor_id,
  created_at: ts()
};

let memRes = await sbFetch("/rest/v1/members?select=id", {
  method: "POST",
  body: JSON.stringify(memberPayload)
});
results.step9_member = { http: memRes.status, body: memRes.body };
console.log("Member:", memRes.status, JSON.stringify(memRes.body).slice(0, 200));

// === STEP 10: Investor created (CRM) ===
console.log("\n=== STEP 10: Investor Created (CRM) ===");
const investorPayload = {
  name: "John Visitor",
  email: regEmail,
  phone: "+1-305-555-0142",
  country: "US",
  city: "Miami",
  investor_type: "real_estate",
  capital_range: "500k-2M",
  status: "new_lead",
  source: "intent_engine",
  search_query: searchQuery,
  landing_page: "/invest-miami",
  visitor_id: visitorPayload.visitor_id,
  intent_score: 92,
  buying_intent_score: 78,
  investment_intent_score: 92,
  probability_of_registration: 0.34,
  probability_of_investment: 0.12,
  created_at: ts()
};

let invRes = await sbFetch("/rest/v1/investors?select=id", {
  method: "POST",
  body: JSON.stringify(investorPayload)
});
results.step10_investor = { http: invRes.status, body: invRes.body };
console.log("Investor:", invRes.status, JSON.stringify(invRes.body).slice(0, 200));

// === STEP 11: CRM updated ===
console.log("\n=== STEP 11: CRM Updated ===");
let crmUpdate = null;
if (invRes.body && invRes.body[0]?.id) {
  crmUpdate = await sbFetch(`/rest/v1/investors?id=eq.${invRes.body[0].id}`, {
    method: "PATCH",
    headers: { "Prefer": "return=representation" },
    body: JSON.stringify({ 
      status: "qualified",
      last_contact: ts(),
      notes: "AI conversation started. High intent score 92. Interested in Miami investment property.",
      updated_at: ts()
    })
  });
}
results.step11_crm = { http: crmUpdate?.status, body: crmUpdate?.body };
console.log("CRM update:", crmUpdate?.status, JSON.stringify(crmUpdate?.body).slice(0, 200));

// === STEP 12: Analytics updated ===
console.log("\n=== STEP 12: Analytics Updated ===");
const analyticsPayload = {
  event_type: "visitor_conversion",
  visitor_id: visitorPayload.visitor_id,
  event_data: {
    search_query: searchQuery,
    landing_page: "/invest-miami",
    country: "US",
    language: "en",
    device: "mobile",
    ai_conversation: true,
    registered: true,
    became_member: true,
    became_investor: true,
    intent_score: 92
  },
  created_at: ts()
};

let anRes = await sbFetch("/rest/v1/analytics_events?select=id", {
  method: "POST",
  body: JSON.stringify(analyticsPayload)
});
results.step12_analytics = { http: anRes.status, body: anRes.body };
console.log("Analytics:", anRes.status, JSON.stringify(anRes.body).slice(0, 200));

// === STEP 13: Autonomous follow-up scheduled ===
console.log("\n=== STEP 13: Autonomous Follow-up Scheduled ===");
const followupPayload = {
  visitor_id: visitorPayload.visitor_id,
  investor_email: regEmail,
  followup_type: "email",
  scheduled_for: new Date(Date.now() + 86400000).toISOString(), // 24h
  status: "scheduled",
  message_template: "miami_investment_followup",
  priority: "high",
  source: "autonomous_optimization",
  created_at: ts()
};

let fuRes = await sbFetch("/rest/v1/follow_ups?select=id", {
  method: "POST",
  body: JSON.stringify(followupPayload)
});
results.step13_followup = { http: fuRes.status, body: fuRes.body };
console.log("Follow-up:", fuRes.status, JSON.stringify(fuRes.body).slice(0, 200));

// === STEP 14: Email/SMS sequence created ===
console.log("\n=== STEP 14: Email/SMS Sequence ===");
const seqPayload = {
  visitor_id: visitorPayload.visitor_id,
  email: regEmail,
  phone: "+1-305-555-0142",
  sequence_name: "miami_investor_nurture",
  steps: [
    { day: 0, channel: "email", template: "welcome_miami" },
    { day: 1, channel: "email", template: "miami_roi_report" },
    { day: 3, channel: "sms", template: "schedule_call_reminder" },
    { day: 7, channel: "email", template: "investment_opportunities" }
  ],
  status: "active",
  created_at: ts()
};

let seqRes = await sbFetch("/rest/v1/communication_sequences?select=id", {
  method: "POST",
  body: JSON.stringify(seqPayload)
});
results.step14_sequence = { http: seqRes.status, body: seqRes.body };
console.log("Sequence:", seqRes.status, JSON.stringify(seqRes.body).slice(0, 200));

// === STEP 15: Dashboard updated (verify counts) ===
console.log("\n=== STEP 15: Dashboard Updated ===");
const dashRes = await fetch(`${API}/api/ivx/intent/dashboard`, {
  method: "GET",
  headers: { "Content-Type": "application/json" }
});
const dashStatus = dashRes.status;
let dashBody;
try { dashBody = await dashRes.json(); } catch { dashBody = await dashRes.text(); }
results.step15_dashboard = { http: dashStatus, body: typeof dashBody === 'object' ? JSON.stringify(dashBody).slice(0, 500) : String(dashBody).slice(0, 500) };
console.log("Dashboard:", dashStatus, typeof dashBody === 'object' ? JSON.stringify(dashBody).slice(0, 300) : String(dashBody).slice(0, 300));

// Also get live counts from Supabase
const counts = {};
for (const [table, col] of [["intent_keywords","id"],["visitor_intelligence","id"],["waitlist","id"],["members","id"],["investors","id"],["analytics_events","id"],["follow_ups","id"],["communication_sequences","id"]]) {
  const c = await sbFetch(`/rest/v1/${table}?select=${col}&limit=1`, { headers: { "Prefer": "count=exact" } });
  const count = c.body && Array.isArray(c.body) ? c.body.length : 0;
  const header = c.status;
  counts[table] = { http: header, rows_returned: count };
}
results.live_counts = counts;

// === FINAL OUTPUT ===
results.timestamp = ts();
results.supabase_url = SUPABASE_URL;
results.api_url = API;
console.log("\n=== FULL JOURNEY RESULTS ===");
console.log(JSON.stringify(results, null, 2));

// Save proof
const fs = await import('fs');
fs.writeFileSync('/tmp/visitor-journey-proof.json', JSON.stringify(results, null, 2));
console.log("\nProof saved to /tmp/visitor-journey-proof.json");
SCRIPT
node /tmp/visitor-journey.mjs 2>&1

